const d = $input.first().json;
const meta = d.metadata || {};
const seg = Array.isArray(d.transcript) ? d.transcript : [];
const vid = d.video_id;
const videoUrl = 'https://www.youtube.com/watch?v=' + vid;
const picks = [];
if (seg.length) { const n = Math.min(4, seg.length); for (let i = 0; i < n; i++) { picks.push(seg[Math.floor((i + 0.5) * seg.length / n)]); } }
return [ { json: { videoId: vid, videoUrl, author: meta.author_name || null, authorUrl: meta.author_url || null, title: meta.title || vid, snippetSegments: picks } } ];

function ts(sec) {
  const s = Math.floor(sec || 0);
  const h = Math.floor(s / 3600), m = Math.floor((s % 3600) / 60), r = s % 60;
  const mm = (r < 10 ? '0' : '') + r;
  return h > 0 ? (h + ':' + (m < 10 ? '0' : '') + m + ':' + mm) : (m + ':' + mm);
}
const s = $json;
const author = s.author || '[Author / channel — verify]';
const title = s.title;
const url = s.videoUrl;
const accessed = new Date().toISOString().slice(0, 10);
const apa = author + ' (n.d.). ' + title + ' [Video]. YouTube. ' + url;
const mla = '"' + title + '." YouTube, uploaded by ' + author + ', ' + url + '. Accessed ' + accessed + '.';
const chicago = author + '. "' + title + '." YouTube video. Accessed ' + accessed + '. ' + url + '.';
const key = ('youtube_' + (s.videoId || 'video')).replace(/[^A-Za-z0-9_]/g, '');
const bibtex = '@misc{' + key + ',\n  author = {' + author + '},\n  title = {' + title + '},\n  howpublished = {YouTube video},\n  note = {Accessed: ' + accessed + '},\n  url = {' + url + '}\n}';
const snippets = (s.snippetSegments || []).map((seg) => {
  const sec = Math.floor(seg.start || 0);
  const tsMark = ts(sec);
  const deep = url + '&t=' + sec + 's';
  return { timestamp: tsMark, seconds: sec, quote: seg.text, deepLink: deep, intext_citation: '(' + author + ', ' + tsMark + ')' };
});
return [ { json: {
  videoUrl: url,
  author,
  title,
  citations: { apa, mla, chicago, bibtex },
  accessed,
  snippets,
  caveat: 'Citation templates only. The API does not provide a publication date (shown as n.d.) and the author is the channel name — verify both. Confirm the exact style edition required (APA 7, MLA 9, Chicago 17) and any institution or publisher requirements before submitting.',
} } ];
